DROP TABLE IF EXISTS `system_task_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `system_task_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `task_name` varchar(50) NOT NULL COMMENT 'Tên nhiệm vụ',
  `execute_date` date NOT NULL COMMENT 'Ngày thực thi',
  `execute_time` datetime NOT NULL COMMENT 'Thời gian thực thi',
  `result` text COMMENT 'Kết quả thực thi',
  `created_at` int(11) NOT NULL COMMENT 'Thời gian tạo',
  PRIMARY KEY (`id`),
  KEY `idx_task_date` (`task_name`,`execute_date`)
) ENGINE=InnoDB AUTO_INCREMENT=91 DEFAULT CHARSET=utf8mb4 COMMENT='Nhật ký thực thi tác vụ định kỳ';
